   168	  AssertFatal(eutra_bandP != 64, "LTE b64 is a reserved band");
   169	  AssertFatal(dl_CarrierFreq_by_100k >= eutra_bandtable[i].dl_min,
   170	              "Band %d, bw %u : DL carrier frequency %lld Hz < %u\n",
   171	              eutra_bandP, bw, dl_CarrierFreq,
   172	              eutra_bandtable[i].dl_min);
   173	  AssertFatal(dl_CarrierFreq_by_100k <=
   174	              (eutra_bandtable[i].dl_max - bw_by_100),
   175	              "Band %d, bw %u : DL carrier frequency %lld Hz > %d\n",
   176	              eutra_bandP, bw, dl_CarrierFreq,
   177	              eutra_bandtable[i].dl_max - bw_by_100);
   178	  return (dl_CarrierFreq_by_100k - eutra_bandtable[i].dl_min +
   179	          (eutra_bandtable[i].N_OFFs_DL / 10));
